// Hierarchical beta-binomial model
// y_i ~ Binomial(n_i, theta_i)
// theta_i ~ Beta(alpha, beta)
// prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
data {
  int<lower=0> N;            // number of observations
  int<lower=0> n[N];         // trials
  int<lower=0> y[N];         // successes
}
parameters {
  real<lower=0> alpha;
  real<lower=0> beta;
  vector<lower=0, upper=1>[N] theta;
}
model {
  // Prior proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);
  // Group-level Beta prior for each theta_i
  theta ~ beta(alpha, beta);
  // Binomial likelihood
  y ~ binomial(n, theta);
}
